import{c as e,Q as s,j as a,m as n}from"./chunks/framework.BPKcPtvA.js";const c=JSON.parse('{"title":"How do I assign a user to a tenant?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/portal/assign-user-to-tenant.md","filePath":"guide/recipes/portal/assign-user-to-tenant.md","lastUpdated":1778912818000}'),o={name:"guide/recipes/portal/assign-user-to-tenant.md"};function r(i,t,l,d,u,h){return s(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="how-do-i-assign-a-user-to-a-tenant" tabindex="-1">How do I assign a user to a tenant? <a class="header-anchor" href="#how-do-i-assign-a-user-to-a-tenant" aria-label="Permalink to &quot;How do I assign a user to a tenant?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Owner</strong> or <strong>Admin</strong></p></div><p>A user must exist at the customer level first (see <a href="./invite-user">invite a user</a>). Assigning them to a tenant provisions their account inside that tenant with a tenant role — Tenant Admin or Tenant User.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Users</strong> in the sidebar and click the row of the user you want to assign. The row expands.</li><li>In the <strong>Tenant Assignments</strong> section, click <strong>Assign to Tenant</strong>.</li><li>Pick the tenant from the dropdown.</li><li>Pick the <strong>tenant role</strong>: <ul><li><strong>Tenant Admin</strong> — full admin within that tenant.</li><li><strong>Tenant User</strong> — regular user.</li></ul></li><li>Click <strong>Assign</strong>.</li></ol><div class="tip custom-block"><p class="custom-block-title">Faster path</p><p>You can also start from the tenant detail page: open <strong>Tenants → &lt;tenant name&gt; → Users → Assign Users</strong>. Same dialog, just scoped to that tenant.</p></div><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The user is provisioned into the tenant immediately. They show up in <strong>Tenants → &lt;tenant name&gt; → Users</strong> with the role you picked, and on their detail row the new assignment appears in the <strong>Tenant Assignments</strong> list.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./bulk-assign-users">How do I bulk-assign users to a tenant?</a></li><li><a href="./change-user-role">How do I change a user&#39;s portal role?</a></li><li><a href="./remove-user">How do I remove a user from my customer?</a></li></ul>',10)])])}const p=e(o,[["render",r]]);export{c as __pageData,p as default};
